  ('elementary-0489de64-moex-00371', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '綠色運輸旨在促進更加環保和可持續的運輸方式。下列那項措施最能體現綠色運輸的核心理念？', '["為所有運輸工具安裝更快速的引擎，提高運輸效率", "在城市中心區域增設收費站，減少車輛進入並降低交通擁堵", "鼓勵使用電動車輛和公共交通工具，減少碳排放和環境污染", "增加航班數量，提供乘客更多的旅行選擇和便利性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00372', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列何者為交通部公路局補助電動大客車之項目？①車輛購置金額全額補助  ②低底盤大客車增額', '["運送至離島地區之運費補助", "配備具自駕等級第三級以上之增額補助", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00373', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '複合運輸系統（IntermodalTransportationSystem）是指將二種或以上的運輸工具或運輸模式予以整合， 以提高整體運輸效率和便利性。下列那項描述能準確地反映複合運輸系統之主要特點？', '["複合運輸系統僅限於結合公路運輸和海洋運輸", "複合運輸系統的主要目標是完全取代所有單一運輸模式", "複合運輸系統強調在不同運輸階段使用最適合的運輸工具或運輸模式，發揮各自之效益，以最經濟 有效的方式來完成運送", "複合運輸系統專注於提供高速運輸服務，而不考慮成本或環境影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00374', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列那一項措施的目的在降低車速，同時可提升行人通過路口安全性？', '["設置窄式快慢分隔島", "行穿線貼齊路緣", "縮短路緣轉角半徑", "使用交通號誌連鎖"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00375', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '假設政府放寬公車的使用年限（例如由 8年變成 10年），對公車業者營運成本影響的敘述何者 正確？', '["車輛之道路交通事故風險必定增加", "車輛之殘值必定增加", "每年每車之維修成本必定降低", "每車之折舊成本必定降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00376', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '一家海運公司為迎合特定型號大型貨輪的需求，與國家合作採BOT投資建造深水貨櫃碼頭。但投資 完工後不久，這家海運公司發現貨輪的實際運輸量遠低於預期，導致所投資碼頭大多數時間閒置。這 種因為閒置無法做為其他用途之投資成本，可稱為那一種成本項目？', '["機會成本", "沉沒成本", "固定成本", "變動成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00377', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '需求反應式運輸服務（DRTS）的公共交通運輸模式，其運營方式不同於傳統之公共交通運輸系統。 下列那項描述最能準確地反映DRTS的核心特點？', '["DRTS完全依賴固定的路線和時刻表，並不根據乘客的即時需求進行調整", "DRTS主要運營於高密度人口區域，需要營運班次密度較高的派遣", "DRTS僅限於計程車共乘服務，不包括其它型式的運輸服務，如：撥召公車、彈性運輸服務等", "DRTS可依據乘客的即時需求，動態調整路線或發車時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00378', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列何者不是航空貨運業者選擇機場所考量之因素？', '["機場收費", "宵禁限制", "飛行時間和成本", "機場附近地區民眾平均所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00379', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列何者為運輸管制可採取之措施？①報酬率管制  ②營運比管制  ③價格管制  ④數量管制 ⑤服務品質管制  ⑥乘客來源管制', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00380', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '「反托拉斯法」旨在防止企業之間的不公平競爭和市場壟斷，確保市場之公平與效率。下列那項行為 是運輸業違反「反托拉斯法」之原因？', '["該公司提供比競爭對手更低的運輸服務價格", "該公司與其他幾家運輸公司秘密協議，共同設定運輸服務的價格和市場分配", "該公司開發一種新的運輸技術，使其在市場上擁有技術優勢", "該公司提高運輸服務的質量，以吸引更多的客戶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
